+function resolveWsTransport(options: Parameters<StreamFn>[2]): WsTransport {
+  const transport = (options as { transport?: unknown } | undefined)?.transport;
+  return transport === "sse" || transport === "websocket" || transport === "auto"
+    ? transport
+    : "auto";
